import{_ as o,o as a,c as r,a2 as i}from"./chunks/framework.BWuWLRhz.js";const m=JSON.parse('{"title":"Open Core Boundary","description":"","frontmatter":{},"headers":[],"relativePath":"reference/open-core.md","filePath":"reference/open-core.md","lastUpdated":null}'),n={name:"reference/open-core.md"};function l(t,e,c,s,d,p){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="open-core-boundary" tabindex="-1">Open Core Boundary <a class="header-anchor" href="#open-core-boundary" aria-label="Permalink to &quot;Open Core Boundary&quot;">​</a></h1><p>Autofac is open core. The core platform is Apache-2.0 and self-hostable. A separately licensed commercial tier adds enterprise governance, scale, and operations features.</p><h2 id="open-source-core" tabindex="-1">Open source core <a class="header-anchor" href="#open-source-core" aria-label="Permalink to &quot;Open source core&quot;">​</a></h2><p>The open-source distribution is intended to run a governed AI software-delivery workflow end to end on your own infrastructure.</p><p>It includes:</p><ul><li>BPMN-native workflow engine.</li><li>Postgres-backed durable checkpoints.</li><li>Agent orchestration.</li><li>Policy-enforced Tool Gateway.</li><li>Hook Gateway.</li><li>Skill repository and prompt assembler.</li><li>Docker-sandboxed agent execution.</li><li>GitHub connector for issues, branches, pull requests, and reviews.</li><li>CI/CD trigger support.</li><li>Approval gates.</li><li>Evidence-pack export.</li><li>Artifact storage.</li><li>Audit log.</li><li>Web UI for workflow design, runs, run detail, and approvals.</li><li>Tokenless mock model provider for demos and CI.</li></ul><h2 id="commercial-tier" tabindex="-1">Commercial tier <a class="header-anchor" href="#commercial-tier" aria-label="Permalink to &quot;Commercial tier&quot;">​</a></h2><p>Commercial capabilities are layered on top:</p><ul><li>Enterprise SSO/OIDC and fine-grained RBAC.</li><li>Multi-tenant control plane and managed/hosted offering.</li><li>Advanced policy and compliance packs.</li><li>Long-horizon evidence and audit retention.</li><li>Horizontal worker scaling and queue-based dispatch at scale.</li><li>Priority support and SLAs.</li></ul><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ul><li>Open-source features should not move behind the commercial tier.</li><li>Self-hosting remains first-class.</li><li>Contributions to the open core are welcome under Apache-2.0.</li></ul><h2 id="documentation-convention" tabindex="-1">Documentation convention <a class="header-anchor" href="#documentation-convention" aria-label="Permalink to &quot;Documentation convention&quot;">​</a></h2><p>Manual pages should label commercial-only features in context. Do not make an open-source operator discover a feature boundary only after following setup instructions.</p>',13)])])}const h=o(n,[["render",l]]);export{m as __pageData,h as default};
